// src/components/Navbar.jsx

import { FaHome, FaSignOutAlt } from "react-icons/fa";

export default function Navbar() {

  const logout = () => {
    localStorage.removeItem("user");
    window.location = "/";
  };

  return (

    <div style={styles.navbar}>

      {/* LEFT */}
      <div style={styles.logoBox}>

        <div style={styles.logoCircle}>
          D
        </div>

        <h2 style={styles.logoText}>
          DailyMajdoor
        </h2>

      </div>

      {/* RIGHT */}
      <div style={styles.menu}>

        <button
          style={styles.homeBtn}
          onClick={() => window.location = "/"}
        >
          <FaHome />
          Home
        </button>

        <button
          style={styles.logoutBtn}
          onClick={logout}
        >
          <FaSignOutAlt />
          Logout
        </button>

      </div>

    </div>
  );
}

const styles = {

  navbar: {
    height: "80px",
    background: "#0f172a",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "0 60px",
    borderBottom: "1px solid rgba(255,255,255,0.08)",
    boxShadow: "0 6px 25px rgba(0,0,0,0.25)"
  },

  logoBox: {
    display: "flex",
    alignItems: "center",
    gap: "14px"
  },

  logoCircle: {
    width: "42px",
    height: "42px",
    borderRadius: "12px",
    background: "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontWeight: "bold",
    fontSize: "18px"
  },

  logoText: {
    fontSize: "24px",
    color: "white",
    margin: 0,
    fontWeight: "700"
  },

  menu: {
    display: "flex",
    gap: "14px"
  },

  homeBtn: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    background: "rgba(255,255,255,0.08)",
    border: "1px solid rgba(255,255,255,0.08)",
    color: "white",
    padding: "12px 22px",
    borderRadius: "12px",
    cursor: "pointer",
    fontWeight: "600",
    fontSize: "14px"
  },

  logoutBtn: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    background: "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    border: "none",
    padding: "12px 22px",
    borderRadius: "12px",
    cursor: "pointer",
    fontWeight: "600",
    fontSize: "14px",
    boxShadow: "0 8px 20px rgba(249,115,22,0.35)"
  }

};
